MOD = 1000000007

class Fancy:
    def __init__(self):
        self.seq = []
        self.mult = 1
        self.add = 0

    def append(self, val):
        inv = pow(self.mult, MOD - 2, MOD)
        raw = ((val - self.add) * inv) % MOD
        self.seq.append(raw)

    def addAll(self, inc):
        self.add = (self.add + inc) % MOD

    def multAll(self, m):
        self.mult = (self.mult * m) % MOD
        self.add = (self.add * m) % MOD

    def getIndex(self, idx):
        if idx >= len(self.seq):
            return -1
        return (self.seq[idx] * self.mult + self.add) % MOD

