class Fancy {
    constructor() {
        this.MOD = 1000000007n;
        this.seq = [];
        this.mult = 1n;
        this.add = 0n;
    }

    _modpow(base, exp, mod) {
        base %= mod;
        let result = 1n;
        while (exp > 0n) {
            if (exp & 1n) result = (result * base) % mod;
            base = (base * base) % mod;
            exp >>= 1n;
        }
        return result;
    }

    append(val) {
        const inv = this._modpow(this.mult, this.MOD - 2n, this.MOD);
        let raw = ((BigInt(val) - this.add) % this.MOD + this.MOD) % this.MOD;
        raw = (raw * inv) % this.MOD;
        this.seq.push(raw);
    }

    addAll(inc) {
        this.add = (this.add + BigInt(inc)) % this.MOD;
    }

    multAll(m) {
        const bm = BigInt(m);
        this.mult = (this.mult * bm) % this.MOD;
        this.add = (this.add * bm) % this.MOD;
    }

    getIndex(idx) {
        if (idx >= this.seq.length) return -1;
        const val = (this.seq[idx] * this.mult + this.add) % this.MOD;
        return Number(val);
    }
}
